<?php
 declare(strict_types=1); namespace tapmeppe\composer\summons; use tapmeppe\composer\blueprint\Resources; use tapmeppe\composer\helpers\Abcd; class AbcdViewsExtension extends \Illuminate\Console\Command { protected $signature = 'governance:abcd:views-extension'; protected $description = 'Add the blade components of the governance⚙️ extension to the views.'; public function handle() { $suffixes = (object)[ 'active' => ['head', 'body',], 'deprecated' => ['foot'], ]; $errors = 0; $folders = []; $root = dirname(__DIR__, 4); switch (Abcd::getTool()) { case 'accounting': case 'laravel': $folders = [ 'resources/views' => [ 'vendor/', ], ]; break; case 'contacts': $folders = [ 'packages/Webkul/Admin/src/Resources/views' => [], 'packages/Webkul/Installer/src/Resources/views' => [], 'packages/Webkul/WebForm/src/Resources/views' => [], ]; break; } foreach ($folders as $folder => $flags) { $this->info("Processing folder '$folder' ..."); Resources::listRecursive( $directory = "$root/$folder", function ($name, $path) use ($directory, &$errors, $flags, $suffixes) { if (str_ends_with($name, '.blade.php')) { $content = Resources::read($path); $prefix = str_replace("$directory/", '', $path); foreach ($suffixes->deprecated as $suffix) { $component = "<x-governance-$suffix/>"; if (str_contains($content, $component)) { $message = "- $prefix > $suffix -"; if (Resources::write($path, $content = str_replace($component, '', $content))) $this->info("$message REMOVED"); else { $this->info("$message FAILED to remove"); $errors++; } } } foreach ($flags as $flag) if (str_starts_with($prefix, $flag)) return; foreach ($suffixes->active as $suffix) { $component = "<x-governance-$suffix/>"; $tag = "</$suffix>"; $message = "- $prefix > $suffix -"; if (str_contains($content, $component) || !str_contains($content, $tag)) continue; elseif (Resources::write($path, $content = str_replace($tag, $component . $tag, $content))) $this->info("$message added"); else { $this->info("$message FAILED to add"); $errors++; } } } } ); } $this->info("Done. $errors errors."); exit($errors); } } 